using UnityEngine;

public class GrindableSurface : MonoBehaviour
{
    [Header("Surface Properties")]
    public float grindingSpeed = 5f; // The speed at which the player will move along the grind

    // These transforms represent the start and end points of the grindable rail. Assign these in the inspector or dynamically
    public Transform startTransform;
    public Transform endTransform;

    // Returns the direction from the nearest point on the rail to the end point in relation to the player’s approach direction.
    public Vector3 GetGrindDirection(Vector3 playerPosition, Vector3 playerDirection)
    {
        // Find the closest point on the line segment to the player position
        Vector3 nearestPointOnRail = NearestPointOnLine(startTransform.position, endTransform.position, playerPosition);

        // Determine if the player is moving towards the start or end of the rail to decide grinding direction
        Vector3 directionToStart = (startTransform.position - nearestPointOnRail).normalized;
        Vector3 directionToEnd = (endTransform.position - nearestPointOnRail).normalized;

        // Compare the grind direction candidates with the player’s current direction to choose the grinding direction
        if (Vector3.Dot(playerDirection, directionToStart) > Vector3.Dot(playerDirection, directionToEnd))
        {
            return directionToStart;
        }
        else
        {
            return directionToEnd;
        }
    }

    public float GetSpeed()
    {
        return grindingSpeed;
    }

    // Method to calculate a nearest point on a line (rail) given point p
    private Vector3 NearestPointOnLine(Vector3 lineStart, Vector3 lineEnd, Vector3 p)
    {
        Vector3 lineDirection = (lineEnd - lineStart).normalized;
        float distanceFromStart = Vector3.Dot(p - lineStart, lineDirection);
        return lineStart + (lineDirection * distanceFromStart);
    }

    // Debug drawing for the line in the editor
    void OnDrawGizmos()
    {
        if (startTransform != null && endTransform != null)
        {
            Gizmos.DrawLine(startTransform.position, endTransform.position);
        }
    }

    public Vector3 GetGrindPosition(Vector3 currentPosition, Vector3 currentVelocity)
    {
        // Implement the logic to calculate the position during grinding
        // This may involve updating the position based on the grind direction and speed
        return currentPosition + GetGrindDirection(currentPosition, currentVelocity) * GetSpeed() * Time.deltaTime;
    }

    public Vector3 GetGrindVelocity(Vector3 currentVelocity)
    {
        // Implement the logic to calculate the velocity during grinding
        // This may involve updating the velocity based on the grind direction and speed
        return GetGrindDirection(transform.position, currentVelocity) * GetSpeed();
    }

    public Vector3 GetExitPosition(Vector3 currentPosition)
    {
        // Implement the logic to calculate the position when exiting the grind
        // This may involve adjusting the position based on the grind direction and speed
        return currentPosition + GetGrindDirection(currentPosition, Vector3.zero) * GetSpeed() * Time.deltaTime;
    }
}

